function getShift(category: string): "Day" | "Night" | "Full_time" | "Part_time" {
  if (category === "IT") return "Full_time";
  if (category === "NON_IT") return Math.random() > 0.7 ? "Day" : "Full_time";
  return "Day";
}

function getDateRange(category: string): { startDate: string; endDate: string } {
  const bases = [
    { start: "2026-02-01", end: "2026-03-15" }, // Past (Closed)
    { start: "2026-03-01", end: "2026-03-31" }, // Past (Closed)
    { start: "2026-04-01", end: "2026-04-30" }, // Current
    { start: "2026-04-15", end: "2026-05-15" }, // Current
    { start: "2026-05-01", end: "2026-05-31" }, // Future
    { start: "2026-06-01", end: "2026-08-31" }, // Specific: June to August
    { start: "2026-07-01", end: "2026-09-30" }, // Future
  ];
  const idx = Math.floor(Math.random() * bases.length);
  return { startDate: bases[idx].start, endDate: bases[idx].end };
}

function getHrEmail(company: string, _category: string): string {
  return buildDefaultHrEmail(company);
}

export function buildJobRows(
  jobs: Array<{
    title: string; company: string; location: string; salary: string;
    openings: number; applicationLink: string; company2?: string;
  }>,
  category: "IT" | "NON_IT" | "STATE_GOVT" | "CENTRAL_GOVT"
) {
  return jobs.map(j => {
    let { startDate, endDate } = getDateRange(category);
    if (j.title.includes("June-August")) {
      startDate = "2026-06-01";
      endDate = "2026-08-31";
    } else if (j.title.includes("April Fast Track")) {
      startDate = "2026-04-01";
      endDate = "2026-04-30";
    }
    return {
      title: j.title,
      company: j.company,
      category,
      location: j.location,
      shift: getShift(category) as any,
      description: `${j.title} opportunity at ${j.company} in ${j.location}. ${j.company} is seeking qualified professionals to join their team. This role offers competitive compensation of ${j.salary} and an excellent opportunity for career growth in the ${category === "IT" ? "technology" : category === "NON_IT" ? "business" : "government"} sector. You will work with a dynamic team to deliver impactful results and contribute to the organization's mission and goals.`,
      eligibility: COMMON_ELIGIBILITY[category],
      applicationGuide: COMMON_GUIDE[category],
      startDate,
      endDate,
      hrEmail: getHrEmail(j.company, category),
      salary: j.salary,
      openings: j.openings,
      applicationLink: j.applicationLink,
      official_url: j.applicationLink,
    };
  });
}
